import torch
import torch.nn as nn


class Model(nn.Module):
    def __init__(self, in_dim=32, n_classes=10):
        super().__init__()
        self.fc = nn.Linear(in_dim, n_classes)

    def forward(self, x):
        # BUG: didn't flatten before final FC
        return self.fc(x)


def test_output_shape():
    torch.manual_seed(0)
    batch = 8
    n_classes = 10
    model = Model(32, n_classes)
    x = torch.randn(batch, 4, 32)  # includes seq dim
    out = model(x)
    assert out.shape == (batch, n_classes), f'got {out.shape}'


if __name__ == '__main__':
    test_output_shape()
